-- Seed Data: Framework Controls
-- ComplianceForge GRC Platform
--
-- Representative controls for all 9 frameworks. In production, the full control
-- libraries would be imported via the framework import service, but these seeds
-- provide enough data for development, demos, and testing.
--
-- Control UUIDs use pattern: c0000000-XXXX-0000-0000-00000000YYYY
--   XXXX = framework suffix (0001=ISO, 0002=GDPR, etc.)
--   YYYY = sequential control number
--
-- Depends on: frameworks.sql (fixed framework and domain UUIDs)

BEGIN;

-- ============================================================================
-- ISO/IEC 27001:2022 — All 93 Annex A Controls
-- Framework: f0000000-0000-0000-0000-000000000001
-- ============================================================================

-- A.5 Organizational Controls (37 controls)
-- Domain: d0000000-0001-0000-0000-000000000001
INSERT INTO framework_controls (id, framework_id, domain_id, code, title, description, control_type, implementation_type, priority, sort_order) VALUES
('c0000000-0001-0000-0000-000000000001', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.1', 'Policies for information security', 'A set of policies for information security shall be defined, approved by management, published and communicated to relevant personnel and relevant interested parties.', 'directive', 'administrative', 'high', 1),
('c0000000-0001-0000-0000-000000000002', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.2', 'Information security roles and responsibilities', 'Information security roles and responsibilities shall be defined and allocated.', 'directive', 'administrative', 'high', 2),
('c0000000-0001-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.3', 'Segregation of duties', 'Conflicting duties and areas of responsibility shall be segregated.', 'preventive', 'administrative', 'high', 3),
('c0000000-0001-0000-0000-000000000004', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.4', 'Management responsibilities', 'Management shall require all personnel to apply information security in accordance with the established policies and procedures.', 'directive', 'administrative', 'high', 4),
('c0000000-0001-0000-0000-000000000005', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.5', 'Contact with authorities', 'Appropriate contacts with relevant authorities shall be maintained.', 'directive', 'administrative', 'medium', 5),
('c0000000-0001-0000-0000-000000000006', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.6', 'Contact with special interest groups', 'Appropriate contacts with special interest groups or other specialist security forums shall be maintained.', 'directive', 'administrative', 'medium', 6),
('c0000000-0001-0000-0000-000000000007', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.7', 'Threat intelligence', 'Information relating to information security threats shall be collected and analysed to produce threat intelligence.', 'detective', 'administrative', 'high', 7),
('c0000000-0001-0000-0000-000000000008', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.8', 'Information security in project management', 'Information security shall be integrated into project management.', 'preventive', 'administrative', 'medium', 8),
('c0000000-0001-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.9', 'Inventory of information and other associated assets', 'An inventory of information and other associated assets shall be developed and maintained.', 'preventive', 'administrative', 'high', 9),
('c0000000-0001-0000-0000-000000000010', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.10', 'Acceptable use of information and other associated assets', 'Rules for the acceptable use of information and other associated assets shall be identified, documented and implemented.', 'directive', 'administrative', 'medium', 10),
('c0000000-0001-0000-0000-000000000011', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.11', 'Return of assets', 'Personnel and other interested parties shall return all organizational assets in their possession upon change or termination.', 'preventive', 'administrative', 'medium', 11),
('c0000000-0001-0000-0000-000000000012', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.12', 'Classification of information', 'Information shall be classified according to the information security needs of the organization based on confidentiality, integrity, availability and relevant interested party requirements.', 'preventive', 'administrative', 'high', 12),
('c0000000-0001-0000-0000-000000000013', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.13', 'Labelling of information', 'An appropriate set of procedures for information labelling shall be developed and implemented in accordance with the information classification scheme.', 'preventive', 'administrative', 'medium', 13),
('c0000000-0001-0000-0000-000000000014', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.14', 'Information transfer', 'Information transfer rules, procedures, or agreements shall exist for all types of transfer facilities.', 'preventive', 'administrative', 'high', 14),
('c0000000-0001-0000-0000-000000000015', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.15', 'Access control', 'Rules to control physical and logical access to information and other associated assets shall be established and implemented based on business and information security requirements.', 'preventive', 'administrative', 'critical', 15),
('c0000000-0001-0000-0000-000000000016', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.16', 'Identity management', 'The full life cycle of identities shall be managed.', 'preventive', 'technical', 'high', 16),
('c0000000-0001-0000-0000-000000000017', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.17', 'Authentication information', 'Allocation and management of authentication information shall be controlled by a management process including advising personnel on appropriate handling.', 'preventive', 'technical', 'critical', 17),
('c0000000-0001-0000-0000-000000000018', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.18', 'Access rights', 'Access rights to information and other associated assets shall be provisioned, reviewed, modified and removed in accordance with the organization''s topic-specific policy and rules for access control.', 'preventive', 'administrative', 'critical', 18),
('c0000000-0001-0000-0000-000000000019', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.19', 'Information security in supplier relationships', 'Processes and procedures shall be defined and implemented to manage information security risks associated with the use of supplier''s products or services.', 'preventive', 'administrative', 'high', 19),
('c0000000-0001-0000-0000-000000000020', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.20', 'Addressing information security within supplier agreements', 'Relevant information security requirements shall be established and agreed with each supplier.', 'preventive', 'administrative', 'high', 20),
('c0000000-0001-0000-0000-000000000021', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.21', 'Managing information security in the ICT supply chain', 'Processes and procedures shall be defined and implemented to manage information security risks associated with the ICT products and services supply chain.', 'preventive', 'administrative', 'high', 21),
('c0000000-0001-0000-0000-000000000022', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.22', 'Monitoring, review and change management of supplier services', 'The organization shall regularly monitor, review, evaluate and manage change in supplier information security practices and service delivery.', 'detective', 'administrative', 'medium', 22),
('c0000000-0001-0000-0000-000000000023', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.23', 'Information security for use of cloud services', 'Processes for acquisition, use, management and exit from cloud services shall be established in accordance with the organization''s information security requirements.', 'preventive', 'administrative', 'high', 23),
('c0000000-0001-0000-0000-000000000024', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.24', 'Information security incident management planning and preparation', 'The organization shall plan and prepare for managing information security incidents by defining, establishing and communicating processes, roles and responsibilities.', 'corrective', 'administrative', 'critical', 24),
('c0000000-0001-0000-0000-000000000025', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.25', 'Assessment and decision on information security events', 'The organization shall assess information security events and decide if they are to be categorized as information security incidents.', 'detective', 'administrative', 'high', 25),
('c0000000-0001-0000-0000-000000000026', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.26', 'Response to information security incidents', 'Information security incidents shall be responded to in accordance with the documented procedures.', 'corrective', 'administrative', 'critical', 26),
('c0000000-0001-0000-0000-000000000027', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.27', 'Learning from information security incidents', 'Knowledge gained from information security incidents shall be used to strengthen and improve the information security controls.', 'corrective', 'administrative', 'medium', 27),
('c0000000-0001-0000-0000-000000000028', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.28', 'Collection of evidence', 'The organization shall establish and implement procedures for the identification, collection, acquisition and preservation of evidence related to information security events.', 'detective', 'administrative', 'high', 28),
('c0000000-0001-0000-0000-000000000029', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.29', 'Information security during disruption', 'The organization shall plan how to maintain information security at an appropriate level during disruption.', 'corrective', 'administrative', 'high', 29),
('c0000000-0001-0000-0000-000000000030', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.30', 'ICT readiness for business continuity', 'ICT readiness shall be planned, implemented, maintained and tested based on business continuity objectives and ICT continuity requirements.', 'corrective', 'technical', 'high', 30),
('c0000000-0001-0000-0000-000000000031', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.31', 'Legal, statutory, regulatory and contractual requirements', 'Legal, statutory, regulatory and contractual requirements relevant to information security shall be identified, documented and kept up to date.', 'directive', 'administrative', 'high', 31),
('c0000000-0001-0000-0000-000000000032', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.32', 'Intellectual property rights', 'The organization shall implement appropriate procedures to protect intellectual property rights.', 'preventive', 'administrative', 'medium', 32),
('c0000000-0001-0000-0000-000000000033', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.33', 'Protection of records', 'Records shall be protected from loss, destruction, falsification, unauthorized access and unauthorized release.', 'preventive', 'administrative', 'high', 33),
('c0000000-0001-0000-0000-000000000034', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.34', 'Privacy and protection of personal identifiable information (PII)', 'The organization shall identify and meet the requirements regarding the preservation of privacy and protection of PII according to applicable laws, regulations and contractual requirements.', 'preventive', 'administrative', 'critical', 34),
('c0000000-0001-0000-0000-000000000035', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.35', 'Independent review of information security', 'The organization''s approach to managing information security shall be independently reviewed at planned intervals or when significant changes occur.', 'detective', 'administrative', 'medium', 35),
('c0000000-0001-0000-0000-000000000036', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.36', 'Compliance with policies, rules and standards for information security', 'Compliance with the organization''s information security policy, topic-specific policies, rules and standards shall be regularly reviewed.', 'detective', 'administrative', 'medium', 36),
('c0000000-0001-0000-0000-000000000037', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000001', 'A.5.37', 'Documented operating procedures', 'Operating procedures for information processing facilities shall be documented and made available to personnel who need them.', 'directive', 'administrative', 'medium', 37),

-- A.6 People Controls (8 controls)
-- Domain: d0000000-0001-0000-0000-000000000002
('c0000000-0001-0000-0000-000000000038', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.1', 'Screening', 'Background verification checks on all candidates to become personnel shall be carried out prior to joining the organization.', 'preventive', 'administrative', 'high', 38),
('c0000000-0001-0000-0000-000000000039', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.2', 'Terms and conditions of employment', 'Employment contractual agreements shall state the personnel''s and the organization''s responsibilities for information security.', 'directive', 'administrative', 'high', 39),
('c0000000-0001-0000-0000-000000000040', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.3', 'Information security awareness, education and training', 'Personnel and relevant interested parties shall receive appropriate information security awareness, education and training.', 'preventive', 'administrative', 'high', 40),
('c0000000-0001-0000-0000-000000000041', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.4', 'Disciplinary process', 'A disciplinary process shall be formalized and communicated to take action against personnel who have committed an information security violation.', 'corrective', 'administrative', 'medium', 41),
('c0000000-0001-0000-0000-000000000042', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.5', 'Responsibilities after termination or change of employment', 'Information security responsibilities that remain valid after termination or change of employment shall be defined, enforced and communicated.', 'preventive', 'administrative', 'medium', 42),
('c0000000-0001-0000-0000-000000000043', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.6', 'Confidentiality or non-disclosure agreements', 'Confidentiality or non-disclosure agreements reflecting the organization''s needs for the protection of information shall be identified, documented, regularly reviewed and signed.', 'preventive', 'administrative', 'high', 43),
('c0000000-0001-0000-0000-000000000044', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.7', 'Remote working', 'Security measures shall be implemented when personnel are working remotely to protect information accessed, processed or stored outside the organization''s premises.', 'preventive', 'technical', 'high', 44),
('c0000000-0001-0000-0000-000000000045', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000002', 'A.6.8', 'Information security event reporting', 'The organization shall provide a mechanism for personnel to report observed or suspected information security events through appropriate channels in a timely manner.', 'detective', 'administrative', 'high', 45),

-- A.7 Physical Controls (14 controls)
-- Domain: d0000000-0001-0000-0000-000000000003
('c0000000-0001-0000-0000-000000000046', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.1', 'Physical security perimeters', 'Security perimeters shall be defined and used to protect areas that contain information and other associated assets.', 'preventive', 'physical', 'high', 46),
('c0000000-0001-0000-0000-000000000047', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.2', 'Physical entry', 'Secure areas shall be protected by appropriate entry controls and access points.', 'preventive', 'physical', 'high', 47),
('c0000000-0001-0000-0000-000000000048', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.3', 'Securing offices, rooms and facilities', 'Physical security for offices, rooms and facilities shall be designed and implemented.', 'preventive', 'physical', 'medium', 48),
('c0000000-0001-0000-0000-000000000049', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.4', 'Physical security monitoring', 'Premises shall be continuously monitored for unauthorized physical access.', 'detective', 'physical', 'high', 49),
('c0000000-0001-0000-0000-000000000050', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.5', 'Protecting against physical and environmental threats', 'Protection against physical and environmental threats such as natural disasters and other intentional or unintentional physical threats shall be designed and implemented.', 'preventive', 'physical', 'high', 50),
('c0000000-0001-0000-0000-000000000051', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.6', 'Working in secure areas', 'Security measures for working in secure areas shall be designed and implemented.', 'preventive', 'physical', 'medium', 51),
('c0000000-0001-0000-0000-000000000052', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.7', 'Clear desk and clear screen', 'Clear desk rules for papers and removable storage media and clear screen rules for information processing facilities shall be defined and appropriately enforced.', 'preventive', 'physical', 'medium', 52),
('c0000000-0001-0000-0000-000000000053', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.8', 'Equipment siting and protection', 'Equipment shall be sited securely and protected.', 'preventive', 'physical', 'medium', 53),
('c0000000-0001-0000-0000-000000000054', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.9', 'Security of assets off-premises', 'Off-site assets shall be protected.', 'preventive', 'physical', 'medium', 54),
('c0000000-0001-0000-0000-000000000055', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.10', 'Storage media', 'Storage media shall be managed through their life cycle of acquisition, use, transportation and disposal in accordance with the organization''s classification scheme and handling requirements.', 'preventive', 'physical', 'high', 55),
('c0000000-0001-0000-0000-000000000056', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.11', 'Supporting utilities', 'Information processing facilities shall be protected from power failures and other disruptions caused by failures in supporting utilities.', 'preventive', 'physical', 'high', 56),
('c0000000-0001-0000-0000-000000000057', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.12', 'Cabling security', 'Cables carrying power, data or supporting information services shall be protected from interception, interference or damage.', 'preventive', 'physical', 'medium', 57),
('c0000000-0001-0000-0000-000000000058', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.13', 'Equipment maintenance', 'Equipment shall be maintained correctly to ensure availability, integrity and confidentiality of information.', 'preventive', 'physical', 'medium', 58),
('c0000000-0001-0000-0000-000000000059', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000003', 'A.7.14', 'Secure disposal or re-use of equipment', 'Items of equipment containing storage media shall be verified to ensure that any sensitive data and licensed software has been removed or securely overwritten prior to disposal or re-use.', 'preventive', 'physical', 'high', 59),

-- A.8 Technological Controls (34 controls)
-- Domain: d0000000-0001-0000-0000-000000000004
('c0000000-0001-0000-0000-000000000060', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.1', 'User endpoint devices', 'Information stored on, processed by or accessible via user endpoint devices shall be protected.', 'preventive', 'technical', 'high', 60),
('c0000000-0001-0000-0000-000000000061', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.2', 'Privileged access rights', 'The allocation and use of privileged access rights shall be restricted and managed.', 'preventive', 'technical', 'critical', 61),
('c0000000-0001-0000-0000-000000000062', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.3', 'Information access restriction', 'Access to information and other associated assets shall be restricted in accordance with the established topic-specific policy on access control.', 'preventive', 'technical', 'high', 62),
('c0000000-0001-0000-0000-000000000063', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.4', 'Access to source code', 'Read and write access to source code, development tools and software libraries shall be appropriately managed.', 'preventive', 'technical', 'high', 63),
('c0000000-0001-0000-0000-000000000064', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.5', 'Secure authentication', 'Secure authentication technologies and procedures shall be established and implemented based on information access restrictions and the topic-specific policy on access control.', 'preventive', 'technical', 'critical', 64),
('c0000000-0001-0000-0000-000000000065', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.6', 'Capacity management', 'The use of resources shall be monitored and adjusted in line with current and expected capacity requirements.', 'preventive', 'technical', 'medium', 65),
('c0000000-0001-0000-0000-000000000066', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.7', 'Protection against malware', 'Protection against malware shall be implemented and supported by appropriate user awareness.', 'preventive', 'technical', 'critical', 66),
('c0000000-0001-0000-0000-000000000067', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.8', 'Management of technical vulnerabilities', 'Information about technical vulnerabilities of information systems in use shall be obtained, the organization''s exposure to such vulnerabilities shall be evaluated and appropriate measures shall be taken.', 'preventive', 'technical', 'critical', 67),
('c0000000-0001-0000-0000-000000000068', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.9', 'Configuration management', 'Configurations, including security configurations, of hardware, software, services and networks shall be established, documented, implemented, monitored and reviewed.', 'preventive', 'technical', 'high', 68),
('c0000000-0001-0000-0000-000000000069', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.10', 'Information deletion', 'Information stored in information systems, devices or in any other storage media shall be deleted when no longer required.', 'preventive', 'technical', 'medium', 69),
('c0000000-0001-0000-0000-000000000070', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.11', 'Data masking', 'Data masking shall be used in accordance with the organization''s topic-specific policy on access control and other related topic-specific policies, and business requirements, taking applicable legislation into consideration.', 'preventive', 'technical', 'medium', 70),
('c0000000-0001-0000-0000-000000000071', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.12', 'Data leakage prevention', 'Data leakage prevention measures shall be applied to systems, networks and any other devices that process, store or transmit sensitive information.', 'preventive', 'technical', 'high', 71),
('c0000000-0001-0000-0000-000000000072', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.13', 'Information backup', 'Backup copies of information, software and systems shall be maintained and regularly tested in accordance with the agreed topic-specific policy on backup.', 'corrective', 'technical', 'critical', 72),
('c0000000-0001-0000-0000-000000000073', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.14', 'Redundancy of information processing facilities', 'Information processing facilities shall be implemented with redundancy sufficient to meet availability requirements.', 'corrective', 'technical', 'high', 73),
('c0000000-0001-0000-0000-000000000074', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.15', 'Logging', 'Logs that record activities, exceptions, faults and other relevant events shall be produced, stored, protected and analysed.', 'detective', 'technical', 'critical', 74),
('c0000000-0001-0000-0000-000000000075', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.16', 'Monitoring activities', 'Networks, systems and applications shall be monitored for anomalous behaviour and appropriate actions taken to evaluate potential information security events.', 'detective', 'technical', 'critical', 75),
('c0000000-0001-0000-0000-000000000076', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.17', 'Clock synchronization', 'The clocks of information processing systems used by the organization shall be synchronized to approved time sources.', 'preventive', 'technical', 'medium', 76),
('c0000000-0001-0000-0000-000000000077', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.18', 'Use of privileged utility programs', 'The use of utility programs that might be capable of overriding system and application controls shall be restricted and tightly controlled.', 'preventive', 'technical', 'high', 77),
('c0000000-0001-0000-0000-000000000078', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.19', 'Installation of software on operational systems', 'Procedures and measures shall be implemented to securely manage software installation on operational systems.', 'preventive', 'technical', 'high', 78),
('c0000000-0001-0000-0000-000000000079', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.20', 'Networks security', 'Networks and network devices shall be secured, managed and controlled to protect information in systems and applications.', 'preventive', 'technical', 'critical', 79),
('c0000000-0001-0000-0000-000000000080', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.21', 'Security of network services', 'Security mechanisms, service levels and service requirements of network services shall be identified, implemented and monitored.', 'preventive', 'technical', 'high', 80),
('c0000000-0001-0000-0000-000000000081', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.22', 'Segregation of networks', 'Groups of information services, users and information systems shall be segregated in the organization''s networks.', 'preventive', 'technical', 'high', 81),
('c0000000-0001-0000-0000-000000000082', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.23', 'Web filtering', 'Access to external websites shall be managed to reduce exposure to malicious content.', 'preventive', 'technical', 'medium', 82),
('c0000000-0001-0000-0000-000000000083', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.24', 'Use of cryptography', 'Rules for the effective use of cryptography, including cryptographic key management, shall be defined and implemented.', 'preventive', 'technical', 'critical', 83),
('c0000000-0001-0000-0000-000000000084', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.25', 'Secure development life cycle', 'Rules for the secure development of software and systems shall be established and applied.', 'preventive', 'technical', 'high', 84),
('c0000000-0001-0000-0000-000000000085', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.26', 'Application security requirements', 'Information security requirements shall be identified, specified and approved when developing or acquiring applications.', 'preventive', 'technical', 'high', 85),
('c0000000-0001-0000-0000-000000000086', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.27', 'Secure system architecture and engineering principles', 'Principles for engineering secure systems shall be established, documented, maintained and applied to any information system development activities.', 'preventive', 'technical', 'high', 86),
('c0000000-0001-0000-0000-000000000087', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.28', 'Secure coding', 'Secure coding principles shall be applied to software development.', 'preventive', 'technical', 'high', 87),
('c0000000-0001-0000-0000-000000000088', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.29', 'Security testing in development and acceptance', 'Security testing processes shall be defined and implemented in the development life cycle.', 'detective', 'technical', 'high', 88),
('c0000000-0001-0000-0000-000000000089', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.30', 'Outsourced development', 'The organization shall direct, monitor and review the activities related to outsourced system development.', 'preventive', 'administrative', 'medium', 89),
('c0000000-0001-0000-0000-000000000090', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.31', 'Separation of development, test and production environments', 'Development, testing and production environments shall be separated and secured.', 'preventive', 'technical', 'high', 90),
('c0000000-0001-0000-0000-000000000091', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.32', 'Change management', 'Changes to information processing facilities and information systems shall be subject to change management procedures.', 'preventive', 'administrative', 'high', 91),
('c0000000-0001-0000-0000-000000000092', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.33', 'Test information', 'Test information shall be appropriately selected, protected and managed.', 'preventive', 'technical', 'medium', 92),
('c0000000-0001-0000-0000-000000000093', 'f0000000-0000-0000-0000-000000000001', 'd0000000-0001-0000-0000-000000000004', 'A.8.34', 'Protection of information systems during audit testing', 'Audit tests and other assurance activities involving assessment of operational systems shall be planned and agreed between the tester and appropriate management.', 'preventive', 'administrative', 'medium', 93);


-- ============================================================================
-- UK GDPR — Representative articles and requirements
-- Framework: f0000000-0000-0000-0000-000000000002
-- ============================================================================

INSERT INTO framework_controls (id, framework_id, domain_id, code, title, description, control_type, implementation_type, priority, sort_order) VALUES
-- Principles (Domain: d0000000-0002-0000-0000-000000000001)
('c0000000-0002-0000-0000-000000000001', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(1)(a)', 'Lawfulness, fairness and transparency', 'Personal data shall be processed lawfully, fairly and in a transparent manner in relation to the data subject.', 'directive', 'administrative', 'critical', 1),
('c0000000-0002-0000-0000-000000000002', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(1)(b)', 'Purpose limitation', 'Personal data shall be collected for specified, explicit and legitimate purposes and not further processed in a manner that is incompatible with those purposes.', 'directive', 'administrative', 'critical', 2),
('c0000000-0002-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(1)(c)', 'Data minimisation', 'Personal data shall be adequate, relevant and limited to what is necessary in relation to the purposes for which they are processed.', 'directive', 'administrative', 'critical', 3),
('c0000000-0002-0000-0000-000000000004', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(1)(d)', 'Accuracy', 'Personal data shall be accurate and, where necessary, kept up to date.', 'directive', 'administrative', 'high', 4),
('c0000000-0002-0000-0000-000000000005', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(1)(e)', 'Storage limitation', 'Personal data shall be kept in a form which permits identification of data subjects for no longer than is necessary for the purposes for which the personal data are processed.', 'directive', 'administrative', 'high', 5),
('c0000000-0002-0000-0000-000000000006', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(1)(f)', 'Integrity and confidentiality', 'Personal data shall be processed in a manner that ensures appropriate security of the personal data, including protection against unauthorised or unlawful processing and against accidental loss, destruction or damage.', 'directive', 'technical', 'critical', 6),
('c0000000-0002-0000-0000-000000000007', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000001', 'Art.5(2)', 'Accountability', 'The controller shall be responsible for, and be able to demonstrate compliance with, the data protection principles.', 'directive', 'management', 'critical', 7),

-- Lawful Basis (Domain: d0000000-0002-0000-0000-000000000002)
('c0000000-0002-0000-0000-000000000008', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000002', 'Art.6', 'Lawfulness of processing', 'Processing shall be lawful only if and to the extent that at least one lawful basis applies.', 'directive', 'administrative', 'critical', 8),
('c0000000-0002-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000002', 'Art.7', 'Conditions for consent', 'Where processing is based on consent, the controller shall be able to demonstrate that the data subject has consented to processing of his or her personal data.', 'directive', 'administrative', 'high', 9),
('c0000000-0002-0000-0000-000000000010', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000002', 'Art.8', 'Conditions for child consent', 'Where consent applies to information society services offered directly to a child, processing shall be lawful where the child is at least 13 years old.', 'directive', 'administrative', 'high', 10),
('c0000000-0002-0000-0000-000000000011', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000002', 'Art.9', 'Processing of special categories of personal data', 'Processing of special categories of personal data is prohibited unless a specific condition applies.', 'preventive', 'administrative', 'critical', 11),
('c0000000-0002-0000-0000-000000000012', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000002', 'Art.10', 'Processing of criminal conviction data', 'Processing of personal data relating to criminal convictions and offences shall only be carried out under the control of official authority or when authorised by law.', 'preventive', 'administrative', 'high', 12),

-- Data Subject Rights (Domain: d0000000-0002-0000-0000-000000000003)
('c0000000-0002-0000-0000-000000000013', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.12', 'Transparent information and communication', 'The controller shall take appropriate measures to provide information to the data subject in a concise, transparent, intelligible and easily accessible form.', 'directive', 'administrative', 'high', 13),
('c0000000-0002-0000-0000-000000000014', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.13', 'Information to be provided where data is collected from data subject', 'Where personal data are collected from the data subject, the controller shall provide specified information at the time when personal data are obtained.', 'directive', 'administrative', 'high', 14),
('c0000000-0002-0000-0000-000000000015', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.14', 'Information to be provided where data is not obtained from data subject', 'Where personal data have not been obtained from the data subject, the controller shall provide the data subject with specified information.', 'directive', 'administrative', 'high', 15),
('c0000000-0002-0000-0000-000000000016', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.15', 'Right of access by the data subject', 'The data subject shall have the right to obtain from the controller confirmation as to whether or not personal data concerning him or her are being processed.', 'directive', 'administrative', 'critical', 16),
('c0000000-0002-0000-0000-000000000017', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.16', 'Right to rectification', 'The data subject shall have the right to obtain from the controller without undue delay the rectification of inaccurate personal data concerning him or her.', 'corrective', 'administrative', 'high', 17),
('c0000000-0002-0000-0000-000000000018', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.17', 'Right to erasure (right to be forgotten)', 'The data subject shall have the right to obtain from the controller the erasure of personal data concerning him or her without undue delay.', 'corrective', 'technical', 'critical', 18),
('c0000000-0002-0000-0000-000000000019', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.18', 'Right to restriction of processing', 'The data subject shall have the right to obtain from the controller restriction of processing.', 'preventive', 'technical', 'high', 19),
('c0000000-0002-0000-0000-000000000020', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.20', 'Right to data portability', 'The data subject shall have the right to receive the personal data concerning him or her in a structured, commonly used and machine-readable format.', 'directive', 'technical', 'high', 20),
('c0000000-0002-0000-0000-000000000021', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.21', 'Right to object', 'The data subject shall have the right to object, on grounds relating to his or her particular situation, at any time to processing of personal data.', 'preventive', 'administrative', 'high', 21),
('c0000000-0002-0000-0000-000000000022', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000003', 'Art.22', 'Automated individual decision-making, including profiling', 'The data subject shall have the right not to be subject to a decision based solely on automated processing, including profiling, which produces legal effects.', 'preventive', 'technical', 'high', 22),

-- Controller and Processor Obligations (Domain: d0000000-0002-0000-0000-000000000004)
('c0000000-0002-0000-0000-000000000023', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.24', 'Responsibility of the controller', 'The controller shall implement appropriate technical and organisational measures to ensure and to be able to demonstrate that processing is performed in accordance with this Regulation.', 'directive', 'management', 'critical', 23),
('c0000000-0002-0000-0000-000000000024', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.25', 'Data protection by design and by default', 'The controller shall implement appropriate technical and organisational measures for ensuring that, by default, only personal data which are necessary for each specific purpose of the processing are processed.', 'preventive', 'technical', 'critical', 24),
('c0000000-0002-0000-0000-000000000025', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.28', 'Processor', 'Where processing is to be carried out on behalf of a controller, the controller shall use only processors providing sufficient guarantees.', 'preventive', 'administrative', 'high', 25),
('c0000000-0002-0000-0000-000000000026', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.30', 'Records of processing activities', 'Each controller shall maintain a record of processing activities under its responsibility.', 'detective', 'administrative', 'high', 26),
('c0000000-0002-0000-0000-000000000027', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.32', 'Security of processing', 'The controller and the processor shall implement appropriate technical and organisational measures to ensure a level of security appropriate to the risk.', 'preventive', 'technical', 'critical', 27),
('c0000000-0002-0000-0000-000000000028', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.33', 'Notification of a personal data breach to the supervisory authority', 'In the case of a personal data breach, the controller shall without undue delay and, where feasible, not later than 72 hours after having become aware of it, notify the personal data breach to the supervisory authority.', 'corrective', 'administrative', 'critical', 28),
('c0000000-0002-0000-0000-000000000029', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.34', 'Communication of a personal data breach to the data subject', 'When the personal data breach is likely to result in a high risk to the rights and freedoms of natural persons, the controller shall communicate the personal data breach to the data subject without undue delay.', 'corrective', 'administrative', 'critical', 29),
('c0000000-0002-0000-0000-000000000030', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.35', 'Data protection impact assessment', 'Where a type of processing is likely to result in a high risk to the rights and freedoms of natural persons, the controller shall carry out an assessment of the impact of the envisaged processing operations.', 'preventive', 'administrative', 'critical', 30),
('c0000000-0002-0000-0000-000000000031', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000004', 'Art.37', 'Designation of the data protection officer', 'The controller and the processor shall designate a data protection officer in required circumstances.', 'directive', 'management', 'high', 31),

-- International Transfers (Domain: d0000000-0002-0000-0000-000000000005)
('c0000000-0002-0000-0000-000000000032', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000005', 'Art.44', 'General principle for transfers', 'Any transfer of personal data to a third country or international organisation shall take place only if conditions are complied with.', 'preventive', 'administrative', 'critical', 32),
('c0000000-0002-0000-0000-000000000033', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000005', 'Art.46', 'Transfers subject to appropriate safeguards', 'In the absence of an adequacy decision, a controller or processor may transfer personal data only if appropriate safeguards are provided.', 'preventive', 'administrative', 'high', 33),
('c0000000-0002-0000-0000-000000000034', 'f0000000-0000-0000-0000-000000000002', 'd0000000-0002-0000-0000-000000000005', 'Art.49', 'Derogations for specific situations', 'In the absence of an adequacy decision or appropriate safeguards, a transfer may take place only if specific conditions are met.', 'preventive', 'administrative', 'medium', 34);


-- ============================================================================
-- NCSC CAF 3.2 — Cyber Assessment Framework
-- Framework: f0000000-0000-0000-0000-000000000003
-- ============================================================================

INSERT INTO framework_controls (id, framework_id, domain_id, code, title, description, control_type, implementation_type, priority, sort_order) VALUES
-- Objective A: Managing Security Risk (Domain: d0000000-0003-0000-0000-000000000001)
('c0000000-0003-0000-0000-000000000001', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000001', 'A1.a', 'Governance', 'The organisation has appropriate management policies and processes in place to govern its approach to the security of network and information systems.', 'directive', 'management', 'critical', 1),
('c0000000-0003-0000-0000-000000000002', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000001', 'A1.b', 'Roles and responsibilities', 'Appropriate roles and responsibilities are established for the security of network and information systems at all levels.', 'directive', 'management', 'high', 2),
('c0000000-0003-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000001', 'A1.c', 'Decision-making', 'The organisation has appropriate decision-making mechanisms in place to manage security risk.', 'directive', 'management', 'high', 3),
('c0000000-0003-0000-0000-000000000004', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000001', 'A2.a', 'Risk management process', 'The organisation has a systematic approach to identifying, analysing and managing security risks.', 'preventive', 'management', 'critical', 4),
('c0000000-0003-0000-0000-000000000005', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000001', 'A2.b', 'Assurance', 'The organisation has a systematic process for obtaining assurance about the security of network and information systems.', 'detective', 'management', 'high', 5),
('c0000000-0003-0000-0000-000000000006', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000001', 'A3.a', 'Asset management', 'Everything required to deliver the essential function is determined and actively managed.', 'preventive', 'administrative', 'high', 6),

-- Objective B: Protecting Against Cyber Attack (Domain: d0000000-0003-0000-0000-000000000002)
('c0000000-0003-0000-0000-000000000007', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B1.a', 'Policy and process development', 'The organisation defines and communicates appropriate policies to secure its systems.', 'directive', 'administrative', 'high', 7),
('c0000000-0003-0000-0000-000000000008', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B1.b', 'Policy and process implementation', 'The organisation implements its security policies and processes effectively.', 'preventive', 'administrative', 'high', 8),
('c0000000-0003-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B2.a', 'Identity verification, authentication and authorisation', 'The organisation understands, documents and manages access to systems and functions that are important to the essential function.', 'preventive', 'technical', 'critical', 9),
('c0000000-0003-0000-0000-000000000010', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B2.b', 'Device management', 'The organisation manages and maintains devices that are important to the security of the essential function.', 'preventive', 'technical', 'high', 10),
('c0000000-0003-0000-0000-000000000011', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B2.c', 'Privileged user management', 'The organisation closely manages privileged user access to systems that support the essential function.', 'preventive', 'technical', 'critical', 11),
('c0000000-0003-0000-0000-000000000012', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B3.a', 'Understanding data', 'The organisation understands the data important to the essential function, where it is stored, transported and processed.', 'preventive', 'administrative', 'high', 12),
('c0000000-0003-0000-0000-000000000013', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B3.b', 'Data in transit', 'The organisation protects the confidentiality and integrity of data important to the essential function in transit.', 'preventive', 'technical', 'critical', 13),
('c0000000-0003-0000-0000-000000000014', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B3.c', 'Stored data', 'The organisation protects the confidentiality and integrity of stored data important to the essential function.', 'preventive', 'technical', 'critical', 14),
('c0000000-0003-0000-0000-000000000015', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B3.d', 'Mobile data', 'The organisation has an effective approach to managing the risk from mobile data.', 'preventive', 'technical', 'high', 15),
('c0000000-0003-0000-0000-000000000016', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B3.e', 'Media/equipment sanitisation', 'The organisation sanitises or destroys storage media and equipment when appropriate.', 'preventive', 'physical', 'high', 16),
('c0000000-0003-0000-0000-000000000017', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B4.a', 'Secure by design', 'Systems are designed to be secure from the outset.', 'preventive', 'technical', 'critical', 17),
('c0000000-0003-0000-0000-000000000018', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B4.b', 'Secure configuration', 'Systems are securely configured to reduce unnecessary vulnerabilities.', 'preventive', 'technical', 'critical', 18),
('c0000000-0003-0000-0000-000000000019', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B4.c', 'Secure management', 'Systems are managed securely throughout their life cycle.', 'preventive', 'technical', 'high', 19),
('c0000000-0003-0000-0000-000000000020', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B4.d', 'Vulnerability management', 'Known vulnerabilities are effectively managed.', 'preventive', 'technical', 'critical', 20),
('c0000000-0003-0000-0000-000000000021', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B5.a', 'Resilience preparation', 'The organisation has plans and preparation to maintain the essential function in the event of a cyber attack.', 'corrective', 'administrative', 'critical', 21),
('c0000000-0003-0000-0000-000000000022', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B5.b', 'Design for resilience', 'Systems are designed to be resilient to cyber attack.', 'corrective', 'technical', 'high', 22),
('c0000000-0003-0000-0000-000000000023', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B5.c', 'Backups', 'The organisation maintains backups of data, software and configurations necessary to recover the essential function.', 'corrective', 'technical', 'critical', 23),
('c0000000-0003-0000-0000-000000000024', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000002', 'B6.a', 'Staff awareness and training', 'Appropriate staff receive suitable training, awareness and education.', 'preventive', 'administrative', 'high', 24),

-- Objective C: Detecting Cyber Security Events (Domain: d0000000-0003-0000-0000-000000000003)
('c0000000-0003-0000-0000-000000000025', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000003', 'C1.a', 'Monitoring coverage', 'The organisation has comprehensive monitoring coverage of its network and information systems.', 'detective', 'technical', 'critical', 25),
('c0000000-0003-0000-0000-000000000026', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000003', 'C1.b', 'Securing logs', 'The organisation securely stores and manages monitoring data.', 'detective', 'technical', 'high', 26),
('c0000000-0003-0000-0000-000000000027', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000003', 'C1.c', 'Generating alerts', 'The organisation generates timely alerts from monitoring data.', 'detective', 'technical', 'critical', 27),
('c0000000-0003-0000-0000-000000000028', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000003', 'C2.a', 'System abnormalities for attack detection', 'The organisation detects potential cyber attacks through system abnormality detection.', 'detective', 'technical', 'high', 28),
('c0000000-0003-0000-0000-000000000029', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000003', 'C2.b', 'Proactive attack discovery', 'The organisation proactively discovers malicious activity on its network.', 'detective', 'technical', 'high', 29),

-- Objective D: Minimising the Impact of Cyber Security Incidents (Domain: d0000000-0003-0000-0000-000000000004)
('c0000000-0003-0000-0000-000000000030', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000004', 'D1.a', 'Response plan', 'The organisation has an up-to-date incident response plan that is relevant and tested.', 'corrective', 'administrative', 'critical', 30),
('c0000000-0003-0000-0000-000000000031', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000004', 'D1.b', 'Response and recovery capability', 'The organisation has the capability to respond to and recover from a cyber attack.', 'corrective', 'technical', 'critical', 31),
('c0000000-0003-0000-0000-000000000032', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000004', 'D1.c', 'Testing and exercising', 'The organisation regularly tests its response capabilities.', 'detective', 'administrative', 'high', 32),
('c0000000-0003-0000-0000-000000000033', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000004', 'D2.a', 'Lessons learned', 'The organisation learns from security incidents to improve resilience.', 'corrective', 'management', 'medium', 33),
('c0000000-0003-0000-0000-000000000034', 'f0000000-0000-0000-0000-000000000003', 'd0000000-0003-0000-0000-000000000004', 'D2.b', 'Using incidents to drive improvements', 'The organisation uses lessons learned to improve its network and information systems security.', 'corrective', 'management', 'medium', 34);


-- ============================================================================
-- Cyber Essentials — Key controls per technical control area
-- Framework: f0000000-0000-0000-0000-000000000004
-- ============================================================================

INSERT INTO framework_controls (id, framework_id, domain_id, code, title, description, control_type, implementation_type, priority, sort_order) VALUES
-- Firewalls (Domain: d0000000-0004-0000-0000-000000000001)
('c0000000-0004-0000-0000-000000000001', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000001', 'CE1.1', 'Boundary firewalls and internet gateways', 'Boundary firewalls and internet gateways are configured to prevent unauthorised access to and from the internet.', 'preventive', 'technical', 'critical', 1),
('c0000000-0004-0000-0000-000000000002', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000001', 'CE1.2', 'Default admin passwords on firewalls changed', 'Default admin passwords on firewalls are changed before deployment.', 'preventive', 'technical', 'critical', 2),
('c0000000-0004-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000001', 'CE1.3', 'Firewall rules approved and documented', 'Firewall rules are approved and documented, with business justification for each rule.', 'preventive', 'administrative', 'high', 3),
('c0000000-0004-0000-0000-000000000004', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000001', 'CE1.4', 'Unapproved services blocked by default', 'Unapproved services and features are blocked or disabled by default at the firewall.', 'preventive', 'technical', 'high', 4),
('c0000000-0004-0000-0000-000000000005', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000001', 'CE1.5', 'Host-based firewall or equivalent', 'Where devices are mobile or used on untrusted networks, a host-based firewall is enabled.', 'preventive', 'technical', 'high', 5),

-- Secure Configuration (Domain: d0000000-0004-0000-0000-000000000002)
('c0000000-0004-0000-0000-000000000006', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000002', 'CE2.1', 'Unnecessary software removed or disabled', 'Unnecessary software, services and user accounts are removed or disabled.', 'preventive', 'technical', 'high', 6),
('c0000000-0004-0000-0000-000000000007', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000002', 'CE2.2', 'Default passwords changed before deployment', 'Default passwords are changed before deployment of any device or software.', 'preventive', 'technical', 'critical', 7),
('c0000000-0004-0000-0000-000000000008', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000002', 'CE2.3', 'Auto-run and auto-play disabled', 'Auto-run and auto-play features are disabled on all devices.', 'preventive', 'technical', 'medium', 8),
('c0000000-0004-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000002', 'CE2.4', 'Password policy enforced', 'A password policy is in place requiring a minimum password length of at least 8 characters with no maximum length limit.', 'preventive', 'technical', 'high', 9),

-- User Access Control (Domain: d0000000-0004-0000-0000-000000000003)
('c0000000-0004-0000-0000-000000000010', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000003', 'CE3.1', 'User accounts created, approved and managed', 'User accounts are created, approved, and managed through a controlled process.', 'preventive', 'administrative', 'high', 10),
('c0000000-0004-0000-0000-000000000011', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000003', 'CE3.2', 'Admin accounts used only for admin activities', 'Admin accounts are used only for administrative activities, not for day-to-day user tasks.', 'preventive', 'administrative', 'critical', 11),
('c0000000-0004-0000-0000-000000000012', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000003', 'CE3.3', 'Multi-factor authentication used where available', 'Multi-factor authentication is used for all administrator and remote access accounts where available.', 'preventive', 'technical', 'high', 12),
('c0000000-0004-0000-0000-000000000013', 'f0000000-0000-0000-0000-000000000004', 'd0000000-0004-0000-0000-000000000003', 'CE3.4', 'Unnecessary accounts removed or disabled', 'User accounts are removed or disabled when no longer required.', 'preventive', 'administrative', 'high', 13),

-- Malware Protection (Domain: d0000000-0004-0000-0000-000000000004)
