('c0000000-0005-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000001', 'AC-3', 'Access Enforcement', 'Enforce approved authorizations for logical access to information and system resources.', 'preventive', 'technical', 'critical', 3),
