('c0000000-0005-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000002', 'AT-1', 'Policy and Procedures', 'Develop, document, and disseminate awareness and training policy and procedures.', 'directive', 'administrative', 'medium', 9),
