('c0000000-0005-0000-0000-000000000012', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000002', 'AT-4', 'Training Records', 'Document and monitor information security and privacy training activities.', 'detective', 'administrative', 'medium', 12),

