('c0000000-0005-0000-0000-000000000013', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000003', 'AU-1', 'Policy and Procedures', 'Develop, document, and disseminate audit and accountability policy and procedures.', 'directive', 'administrative', 'medium', 13),
('c0000000-0005-0000-0000-000000000014', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000003', 'AU-2', 'Event Logging', 'Identify the types of events that the system is capable of logging in support of the audit function.', 'detective', 'technical', 'high', 14),
