('c0000000-0005-0000-0000-000000000025', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000005', 'CP-1', 'Policy and Procedures', 'Develop, document, and disseminate contingency planning policy and procedures.', 'directive', 'administrative', 'medium', 25),
