('c0000000-0005-0000-0000-000000000046', 'f0000000-0000-0000-0000-000000000005', 'd0000000-0005-0000-0000-000000000009', 'SC-1', 'Policy and Procedures', 'Develop, document, and disseminate system and communications protection policy and procedures.', 'directive', 'administrative', 'medium', 46),
