('c0000000-0006-0000-0000-000000000023', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.AA-03', 'Users, services, and hardware are authenticated', 'Users, services, and hardware are authenticated.', 'preventive', 'technical', 'critical', 23),
('c0000000-0006-0000-0000-000000000024', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.AA-05', 'Access permissions, entitlements, and authorizations are managed', 'Access permissions, entitlements, and authorizations are defined in a policy, managed, enforced, and reviewed.', 'preventive', 'technical', 'high', 24),
('c0000000-0006-0000-0000-000000000025', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.AT-01', 'Personnel are provided awareness and training', 'Personnel are provided with cybersecurity awareness and training so they can perform their cybersecurity-related tasks.', 'preventive', 'administrative', 'high', 25),
('c0000000-0006-0000-0000-000000000026', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.AT-02', 'Individuals in specialized roles are provided awareness and training', 'Individuals in specialized roles are provided with awareness and training so that they possess the knowledge and skills to perform relevant tasks.', 'preventive', 'administrative', 'high', 26),
('c0000000-0006-0000-0000-000000000027', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.DS-01', 'Data-at-rest is protected', 'The confidentiality, integrity, and availability of data-at-rest are protected.', 'preventive', 'technical', 'critical', 27),
('c0000000-0006-0000-0000-000000000028', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.DS-02', 'Data-in-transit is protected', 'The confidentiality, integrity, and availability of data-in-transit are protected.', 'preventive', 'technical', 'critical', 28),
('c0000000-0006-0000-0000-000000000029', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.DS-10', 'Data-in-use is protected', 'The confidentiality, integrity, and availability of data-in-use are protected.', 'preventive', 'technical', 'high', 29),
('c0000000-0006-0000-0000-000000000030', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.PS-01', 'Configuration management practices are established and applied', 'Configuration management practices are established and applied.', 'preventive', 'technical', 'high', 30),
('c0000000-0006-0000-0000-000000000031', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.PS-02', 'Software is maintained, replaced, and removed', 'Software maintenance is performed; software is maintained, replaced, and removed commensurate with risk.', 'preventive', 'technical', 'high', 31),
('c0000000-0006-0000-0000-000000000032', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.IR-01', 'Networks and environments are protected from unauthorized logical access', 'Networks and environments are protected from unauthorized logical access and usage.', 'preventive', 'technical', 'critical', 32),
('c0000000-0006-0000-0000-000000000033', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000003', 'PR.IR-02', 'Technology assets are protected from environmental threats', 'The organization''s technology assets are protected from environmental threats and hazards.', 'preventive', 'physical', 'medium', 33),

-- Detect (DE) — Domain: d0000000-0006-0000-0000-000000000004
('c0000000-0006-0000-0000-000000000034', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.CM-01', 'Networks and network services are monitored', 'Networks and network services are monitored to find potentially adverse events.', 'detective', 'technical', 'critical', 34),
('c0000000-0006-0000-0000-000000000035', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.CM-02', 'The physical environment is monitored', 'The physical environment is monitored to find potentially adverse events.', 'detective', 'physical', 'medium', 35),
('c0000000-0006-0000-0000-000000000036', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.CM-03', 'Personnel activity and technology usage are monitored', 'Personnel activity and technology usage are monitored to find potentially adverse events.', 'detective', 'technical', 'high', 36),
('c0000000-0006-0000-0000-000000000037', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.CM-06', 'External service provider activities and services are monitored', 'External service provider activities and services are monitored to find potentially adverse events.', 'detective', 'administrative', 'high', 37),
('c0000000-0006-0000-0000-000000000038', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.CM-09', 'Computing hardware and software are monitored', 'Computing hardware and software, runtime environments, and their data are monitored to find potentially adverse events.', 'detective', 'technical', 'high', 38),
('c0000000-0006-0000-0000-000000000039', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.AE-02', 'Potentially adverse events are analysed', 'Potentially adverse events are analysed to better understand associated activities.', 'detective', 'technical', 'high', 39),
('c0000000-0006-0000-0000-000000000040', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.AE-03', 'Information is correlated from multiple sources', 'Information is correlated from multiple sources to achieve situational awareness.', 'detective', 'technical', 'high', 40),
('c0000000-0006-0000-0000-000000000041', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000004', 'DE.AE-06', 'Information on adverse events is provided to authorized staff', 'Information on adverse events is provided to authorized staff and tools.', 'detective', 'administrative', 'high', 41),

-- Respond (RS) — Domain: d0000000-0006-0000-0000-000000000005
('c0000000-0006-0000-0000-000000000042', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.MA-01', 'The incident response plan is executed', 'The incident response plan is executed in coordination with relevant third parties once an incident is declared.', 'corrective', 'administrative', 'critical', 42),
('c0000000-0006-0000-0000-000000000043', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.MA-02', 'Incident reports are triaged and validated', 'Incident reports are triaged and validated.', 'detective', 'administrative', 'high', 43),
('c0000000-0006-0000-0000-000000000044', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.MA-03', 'Incidents are categorized and prioritized', 'Incidents are categorized and prioritized.', 'detective', 'administrative', 'high', 44),
('c0000000-0006-0000-0000-000000000045', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.AN-03', 'Analysis is performed to establish what has taken place during an incident', 'Analysis is performed to determine what has taken place during an incident and root cause of the incident.', 'detective', 'technical', 'high', 45),
('c0000000-0006-0000-0000-000000000046', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.MI-01', 'Incidents are contained', 'Incidents are contained.', 'corrective', 'technical', 'critical', 46),
('c0000000-0006-0000-0000-000000000047', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.MI-02', 'Incidents are eradicated', 'Incidents are eradicated.', 'corrective', 'technical', 'critical', 47),
('c0000000-0006-0000-0000-000000000048', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000005', 'RS.CO-02', 'Internal and external stakeholders are notified of incidents', 'Internal and external stakeholders are notified of incidents in accordance with applicable laws, regulations, or policies.', 'corrective', 'administrative', 'high', 48),

-- Recover (RC) — Domain: d0000000-0006-0000-0000-000000000006
('c0000000-0006-0000-0000-000000000049', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000006', 'RC.RP-01', 'The recovery portion of the incident response plan is executed', 'The recovery portion of the incident response plan is executed once initiated from the incident response process.', 'corrective', 'administrative', 'critical', 49),
('c0000000-0006-0000-0000-000000000050', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000006', 'RC.RP-02', 'Recovery actions are selected, scoped, prioritized, and performed', 'Recovery actions are selected, scoped, prioritized, and performed.', 'corrective', 'technical', 'high', 50),
('c0000000-0006-0000-0000-000000000051', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000006', 'RC.RP-03', 'The integrity of backups and other restoration assets is verified', 'The integrity of backups and other restoration assets is verified before using them for restoration.', 'detective', 'technical', 'high', 51),
('c0000000-0006-0000-0000-000000000052', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000006', 'RC.RP-04', 'Critical functions and cybersecurity risk management are considered to establish post-incident operations', 'Critical mission functions and cybersecurity risk management are considered to establish post-incident operational norms.', 'corrective', 'management', 'high', 52),
('c0000000-0006-0000-0000-000000000053', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000006', 'RC.CO-03', 'Recovery activities and progress are communicated to stakeholders', 'Recovery activities and progress in restoring operational capabilities are communicated to designated internal and external stakeholders.', 'corrective', 'administrative', 'medium', 53),
('c0000000-0006-0000-0000-000000000054', 'f0000000-0000-0000-0000-000000000006', 'd0000000-0006-0000-0000-000000000006', 'RC.CO-04', 'Public updates on incident recovery are shared', 'Public updates on incident recovery are shared using approved methods and messaging.', 'corrective', 'administrative', 'medium', 54);


-- ============================================================================
-- PCI DSS v4.0 — Representative requirements
-- Framework: f0000000-0000-0000-0000-000000000007
-- ============================================================================

INSERT INTO framework_controls (id, framework_id, domain_id, code, title, description, control_type, implementation_type, priority, sort_order) VALUES
-- Req 1: Network Security Controls (Domain: d0000000-0007-0000-0000-000000000001)
('c0000000-0007-0000-0000-000000000001', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000001', '1.1.1', 'Network security controls are defined and understood', 'All security policies and operational procedures that are identified in Requirement 1 are documented, kept up to date, in use, and known to all affected parties.', 'directive', 'administrative', 'high', 1),
('c0000000-0007-0000-0000-000000000002', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000001', '1.2.1', 'Network security controls (NSCs) are configured and maintained', 'Configuration standards for NSC rulesets are defined, implemented, and maintained.', 'preventive', 'technical', 'critical', 2),
('c0000000-0007-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000001', '1.2.5', 'All services, protocols, and ports allowed are identified and approved', 'All services, protocols, and ports that are allowed through NSCs are identified, approved, and have a defined business need.', 'preventive', 'technical', 'high', 3),
('c0000000-0007-0000-0000-000000000004', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000001', '1.3.1', 'Inbound traffic to CDE is restricted', 'Inbound traffic to the cardholder data environment (CDE) is restricted to only that which is necessary.', 'preventive', 'technical', 'critical', 4),
('c0000000-0007-0000-0000-000000000005', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000001', '1.3.2', 'Outbound traffic from CDE is restricted', 'Outbound traffic from the cardholder data environment (CDE) is restricted to only that which is necessary.', 'preventive', 'technical', 'high', 5),

-- Req 2: Secure Configurations (Domain: d0000000-0007-0000-0000-000000000002)
('c0000000-0007-0000-0000-000000000006', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000002', '2.1.1', 'Processes and mechanisms for secure configurations are defined', 'All security policies and operational procedures for applying secure configurations are documented, in use, and known to all affected parties.', 'directive', 'administrative', 'high', 6),
('c0000000-0007-0000-0000-000000000007', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000002', '2.2.1', 'Configuration standards are developed, implemented, and maintained', 'Configuration standards are developed, implemented, and maintained for all system components.', 'preventive', 'technical', 'high', 7),
('c0000000-0007-0000-0000-000000000008', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000002', '2.2.2', 'Vendor default accounts managed', 'Vendor default accounts are managed as follows: if default accounts will be used, the default password is changed. If default accounts will not be used, the account is removed or disabled.', 'preventive', 'technical', 'critical', 8),
('c0000000-0007-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000002', '2.2.5', 'All unnecessary functionality is removed or disabled', 'All unnecessary functionality is removed or disabled from system components.', 'preventive', 'technical', 'high', 9),

-- Req 3: Protect Account Data (Domain: d0000000-0007-0000-0000-000000000003)
('c0000000-0007-0000-0000-000000000010', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000003', '3.1.1', 'Processes for protecting account data are defined', 'All security policies and operational procedures for protecting stored account data are documented, in use, and known to all affected parties.', 'directive', 'administrative', 'high', 10),
('c0000000-0007-0000-0000-000000000011', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000003', '3.2.1', 'Account data storage is kept to a minimum', 'Account data storage amount and retention time are limited to that which is required for business, legal, and regulatory purposes.', 'preventive', 'administrative', 'critical', 11),
('c0000000-0007-0000-0000-000000000012', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000003', '3.3.1', 'Sensitive authentication data is not stored after authorisation', 'Sensitive authentication data (SAD) is not retained after authorisation, even if encrypted.', 'preventive', 'technical', 'critical', 12),
('c0000000-0007-0000-0000-000000000013', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000003', '3.4.1', 'PAN is masked when displayed', 'PAN is masked when displayed such that only personnel with a legitimate business need can see more than the first six/last four digits.', 'preventive', 'technical', 'high', 13),
('c0000000-0007-0000-0000-000000000014', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000003', '3.5.1', 'PAN is secured wherever it is stored', 'PAN is secured wherever it is stored through strong cryptography.', 'preventive', 'technical', 'critical', 14),

-- Req 4: Protect Cardholder Data in Transit (Domain: d0000000-0007-0000-0000-000000000004)
('c0000000-0007-0000-0000-000000000015', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000004', '4.1.1', 'Processes for protecting cardholder data in transit are defined', 'All security policies and operational procedures for protecting cardholder data with strong cryptography during transmission are documented and known.', 'directive', 'administrative', 'high', 15),
('c0000000-0007-0000-0000-000000000016', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000004', '4.2.1', 'Strong cryptography protects cardholder data during transmission over open public networks', 'PAN is protected with strong cryptography during transmission over open, public networks.', 'preventive', 'technical', 'critical', 16),

-- Req 5: Malware Protection (Domain: d0000000-0007-0000-0000-000000000005)
('c0000000-0007-0000-0000-000000000017', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000005', '5.2.1', 'An anti-malware solution is deployed on all system components', 'An anti-malware solution is deployed on all system components, except for those system components identified as not at risk from malware.', 'preventive', 'technical', 'critical', 17),
('c0000000-0007-0000-0000-000000000018', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000005', '5.2.2', 'Anti-malware solution detects all known types of malware', 'The anti-malware solution detects all known types of malware and removes, blocks, or contains all known types of malware.', 'detective', 'technical', 'critical', 18),
('c0000000-0007-0000-0000-000000000019', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000005', '5.3.1', 'Anti-malware is kept current', 'Anti-malware solution(s) are kept current via automatic updates.', 'preventive', 'technical', 'high', 19),

-- Req 6: Secure Systems and Software (Domain: d0000000-0007-0000-0000-000000000006)
('c0000000-0007-0000-0000-000000000020', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000006', '6.2.1', 'Custom software is developed securely', 'Bespoke and custom software are developed securely including secure coding practices defined and in use.', 'preventive', 'technical', 'high', 20),
('c0000000-0007-0000-0000-000000000021', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000006', '6.3.1', 'Security vulnerabilities are identified and managed', 'Security vulnerabilities are identified and managed through a vulnerability management process.', 'preventive', 'technical', 'critical', 21),
('c0000000-0007-0000-0000-000000000022', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000006', '6.3.3', 'Critical and high security patches are installed within one month', 'Critical and high security patches/updates are installed within one month of release.', 'preventive', 'technical', 'critical', 22),
('c0000000-0007-0000-0000-000000000023', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000006', '6.4.1', 'Public-facing web applications are protected against attacks', 'For public-facing web applications, threats and vulnerabilities are addressed on an ongoing basis and the application is protected against known attacks.', 'preventive', 'technical', 'critical', 23),

-- Req 7: Restrict Access (Domain: d0000000-0007-0000-0000-000000000007)
('c0000000-0007-0000-0000-000000000024', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000007', '7.2.1', 'Access control model is defined', 'An access control model is defined and includes granting access based on job classification and function.', 'preventive', 'administrative', 'high', 24),
('c0000000-0007-0000-0000-000000000025', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000007', '7.2.2', 'Access is assigned based on individual needs', 'Access is assigned to users, including privileged users, based on job classification and function.', 'preventive', 'administrative', 'high', 25),
('c0000000-0007-0000-0000-000000000026', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000007', '7.2.5', 'All access by application and system accounts is appropriately assigned', 'All access by application and system accounts and related access privileges are assigned and managed.', 'preventive', 'technical', 'high', 26),

-- Req 8: Identify Users and Authenticate Access (Domain: d0000000-0007-0000-0000-000000000008)
('c0000000-0007-0000-0000-000000000027', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000008', '8.2.1', 'All users are assigned a unique ID', 'All users are assigned a unique ID before access to system components or cardholder data is allowed.', 'preventive', 'technical', 'critical', 27),
('c0000000-0007-0000-0000-000000000028', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000008', '8.3.1', 'All user access to system components authenticated', 'All user access to system components for users and administrators is authenticated via at least one authentication factor.', 'preventive', 'technical', 'critical', 28),
('c0000000-0007-0000-0000-000000000029', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000008', '8.3.6', 'Minimum password complexity is enforced', 'If passwords/passphrases are used, minimum length of 12 characters (or 8 if the system does not support 12).', 'preventive', 'technical', 'high', 29),
('c0000000-0007-0000-0000-000000000030', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000008', '8.4.2', 'MFA for all access into the CDE', 'Multi-factor authentication (MFA) is implemented for all access into the cardholder data environment.', 'preventive', 'technical', 'critical', 30),

-- Req 9: Physical Access (Domain: d0000000-0007-0000-0000-000000000009)
('c0000000-0007-0000-0000-000000000031', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000009', '9.2.1', 'Appropriate facility entry controls are in place', 'Appropriate facility entry controls are in place to limit physical access to systems in the cardholder data environment.', 'preventive', 'physical', 'high', 31),
('c0000000-0007-0000-0000-000000000032', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000009', '9.4.1', 'Media with cardholder data is physically secured', 'All media with cardholder data is physically secured.', 'preventive', 'physical', 'high', 32),

-- Req 10: Log and Monitor (Domain: d0000000-0007-0000-0000-000000000010)
('c0000000-0007-0000-0000-000000000033', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000010', '10.2.1', 'Audit logs are enabled and active', 'Audit logs are enabled and active for all system components and cardholder data.', 'detective', 'technical', 'critical', 33),
('c0000000-0007-0000-0000-000000000034', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000010', '10.2.2', 'Audit logs record all required information', 'Audit logs record all events including user identification, type of event, date and time, success or failure, origination of event, and identity or name of affected data.', 'detective', 'technical', 'high', 34),
('c0000000-0007-0000-0000-000000000035', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000010', '10.4.1', 'Audit logs are reviewed to identify anomalies', 'Audit logs are reviewed at least once daily to identify anomalies or suspicious activity.', 'detective', 'administrative', 'critical', 35),

-- Req 11: Test Security (Domain: d0000000-0007-0000-0000-000000000011)
('c0000000-0007-0000-0000-000000000036', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000011', '11.3.1', 'Internal vulnerability scans are performed quarterly', 'Internal vulnerability scans are performed at least once every three months and after any significant change.', 'detective', 'technical', 'high', 36),
('c0000000-0007-0000-0000-000000000037', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000011', '11.3.2', 'External vulnerability scans are performed quarterly', 'External vulnerability scans are performed at least once every three months and after any significant change by a PCI SSC Approved Scanning Vendor (ASV).', 'detective', 'technical', 'high', 37),
('c0000000-0007-0000-0000-000000000038', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000011', '11.4.1', 'External penetration testing is performed', 'External penetration testing is performed at least once every 12 months and after any significant infrastructure or application change.', 'detective', 'technical', 'critical', 38),

-- Req 12: Organisational Policies and Programs (Domain: d0000000-0007-0000-0000-000000000012)
('c0000000-0007-0000-0000-000000000039', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000012', '12.1.1', 'An information security policy is established', 'An overall information security policy is established, published, maintained, and disseminated to all relevant personnel.', 'directive', 'administrative', 'high', 39),
('c0000000-0007-0000-0000-000000000040', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000012', '12.6.1', 'Security awareness training is provided', 'A formal security awareness program is in place to make all personnel aware of the cardholder data security policy and procedures.', 'preventive', 'administrative', 'high', 40),
('c0000000-0007-0000-0000-000000000041', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000012', '12.8.1', 'Service providers with access to cardholder data are managed', 'A list of all third-party service providers with which account data is shared or could affect the security of account data is maintained.', 'preventive', 'administrative', 'high', 41),
('c0000000-0007-0000-0000-000000000042', 'f0000000-0000-0000-0000-000000000007', 'd0000000-0007-0000-0000-000000000012', '12.10.1', 'An incident response plan exists and is ready to be activated', 'An incident response plan exists, is ready to be activated, and includes all elements required by PCI DSS.', 'corrective', 'administrative', 'critical', 42);


-- ============================================================================
-- ITIL 4 — Representative practices
-- Framework: f0000000-0000-0000-0000-000000000008
-- ============================================================================

INSERT INTO framework_controls (id, framework_id, domain_id, code, title, description, control_type, implementation_type, priority, sort_order) VALUES
-- General Management Practices (Domain: d0000000-0008-0000-0000-000000000001)
('c0000000-0008-0000-0000-000000000001', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-SM', 'Strategy Management', 'Formulate the goals of the organisation and adopt the courses of action and allocation of resources necessary for achieving those goals.', 'directive', 'management', 'high', 1),
('c0000000-0008-0000-0000-000000000002', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-PM', 'Portfolio Management', 'Ensure that the organisation has the right mix of programmes, projects, products and services to execute the organisation''s strategy within its funding and resource constraints.', 'directive', 'management', 'high', 2),
('c0000000-0008-0000-0000-000000000003', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-ARCH', 'Architecture Management', 'Provide an understanding of all the different elements that make up an organisation and how those elements interrelate.', 'directive', 'management', 'medium', 3),
('c0000000-0008-0000-0000-000000000004', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-KM', 'Knowledge Management', 'Maintain and improve the effective, efficient, and convenient use of information and knowledge across the organisation.', 'directive', 'administrative', 'medium', 4),
('c0000000-0008-0000-0000-000000000005', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-CSI', 'Continual Improvement', 'Align the organisation''s practices and services with changing business needs through ongoing improvement of products, services, and practices.', 'corrective', 'management', 'high', 5),
('c0000000-0008-0000-0000-000000000006', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-RM', 'Risk Management', 'Ensure that the organisation understands and effectively handles risks to ensure the organisation''s viability and value creation.', 'preventive', 'management', 'critical', 6),
('c0000000-0008-0000-0000-000000000007', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-ISM', 'Information Security Management', 'Protect the information needed by the organisation to conduct its business, including understanding and managing risks to the confidentiality, integrity and availability of information.', 'preventive', 'management', 'critical', 7),
('c0000000-0008-0000-0000-000000000008', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-RRM', 'Relationship Management', 'Establish and nurture the links between the organisation and its stakeholders at strategic and tactical levels.', 'directive', 'management', 'medium', 8),
('c0000000-0008-0000-0000-000000000009', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-SFM', 'Supplier Management', 'Ensure that the organisation''s suppliers and their performances are managed appropriately to support the provision of seamless, quality products and services.', 'preventive', 'administrative', 'high', 9),
('c0000000-0008-0000-0000-000000000010', 'f0000000-0000-0000-0000-000000000008', 'd0000000-0008-0000-0000-000000000001', 'ITIL-WFM', 'Workforce and Talent Management', 'Ensure that the organisation has the right people with the appropriate skills and knowledge and in the correct roles.', 'directive', 'management', 'medium', 10),

-- Service Management Practices (Domain: d0000000-0008-0000-0000-000000000002)
